var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 뒤","JPN":"数日後","ENG":"A few days later","TWN":"幾天後","SCN":"几天后","DEU":"A few days later","FRA":"A few days later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 꼬맹이 뭔가 이상하지 않냐?","JPN":"おい、おこちゃま。おかしくないか？","ENG":"Hey, kid. Doesn't this feel weird to you?","TWN":"喂，小鬼不覺得有點奇怪嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭐가요?","JPN":"何が？","ENG":"What does?","TWN":"什麼？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리가 이 병원 퇴원한 게, 채 한 달도 안 지났다고.","JPN":"私たちがこの病院を退院してから、まだ一か月も経ってないんだけど。","ENG":"It hasn't even been a month since we were discharged from this hospital.","TWN":"我們從這家醫院出院還不到一個月呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"근데 왜 우린 또 여기 입원해 있는 거냐?","JPN":"なのになんで、私たちはまたここに入院してるんだ？","ENG":"So why are we back here again?","TWN":"不過我們為什麼會住院在這裡啊？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"글쎄요? 미라처럼 붕대 둘둘 감은 채로 그런 말 해봤자 소용없지 않을까요?","JPN":"さあ？　ミイラみたいに包帯でぐるぐる巻きにされてそんなこと言っても何も変わらないと思うけど？","ENG":"Well, wrapped up like a mummy in bandages, you're hardly one to complain, don't you think?","TWN":"嗯，被繃帶包得像木乃伊的你，還真沒資格抱怨呢，你不覺得嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"의사 선생님 말씀 못 들었어요? 살아있는 게 기적이라면서요.","JPN":"お医者さんが言ってたでしょ？　生きてるのが奇跡だって。","ENG":"Didn't you hear what the doctor said? Just being alive is a miracle.","TWN":"你沒聽醫生說嗎？活著就是奇蹟。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무렴, 6종 침식체한테 얻어맞았는데 살아 돌아온 게 기적이긴 하지.","JPN":"まあ、第6種侵食体にぶん殴られて、生きて帰れたんだからそりゃ奇跡だろ。","ENG":"Yeah, no kidding. Getting pounded by a Category 6 C.O. and making it out? That's a miracle in itself.","TWN":"當然，被6類侵蝕體打了還能活著回來確實是個奇蹟。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 무저갱에서 보냈던 시간이 현실에서는 고작 3시간 남짓이었다는 게 말이 되냐?","JPN":"あの奈落の底にいた時間が、現実ではたったの3時間程度だったなんて、そんなの信じられる？","ENG":"But how do you explain the fact that we spent hours down in that abyss, and only three hours passed in the real world?","TWN":"在那個無底洞中度過的時間在現實中竟然只有短短3小時，這說得通嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아, 진짜 우리 어떻게 살아서 돌아온 거냐?","JPN":"はあ、なんで私たち生きて帰って来れたんだ？","ENG":"*Sigh* How did we even make it back alive?","TWN":"哈，真是的，我們到底是怎麼活著回來的？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"난 아직도 현실감이 안 온다, 야.","JPN":"いまだに現実味がないわ。","ENG":"Still doesn't feel real.","TWN":"我現在都還不太敢相信，哎。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"고마워요, 라이카.","JPN":"ありがとう、ライカ。","ENG":"Thanks, Laika.","TWN":"謝謝你，萊卡。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐야, 뜬금없이? 너도 고백하게?","JPN":"何だ、急に？　あんたも告白でもする気？","ENG":"Huh? Where's that coming from? You about to confess or something?","TWN":"怎麼了，突然這樣？你也要告白嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그, 그런 거 아니라고요!","JPN":"そ、そんなんじゃないわよ！","ENG":"What?! Of course not!","TWN":"不、不是那樣的！"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이번에 라이카가 저를 지켜주느라, 많이 다쳐 버렸으니까…….","JPN":"今回はライカが私を守るために、いっぱい怪我しちゃったから……","ENG":"You got pretty banged up protecting me this time, so...","TWN":"這次為了保護我，萊卡受了重傷……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아서라, 우리는 서로 뒤 봐주는 파트너잖아? 때때로 포지션을 바꿔 줄 필요도 있는 거지.","JPN":"よせって。私たちは互いに尻拭いするパートナーだろ？　たまにはポジションを変えてみるのも悪くないってもんだ。","ENG":"Come on, we've always got each other's backs. Just means it was my turn to take the hit.","TWN":"亞瑟拉，我們是互相照應的夥伴吧？有時候也需要換換位置呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으아, 저질이에요. 라이카. 완전 아저씨 같아.","JPN":"うわっ、最低。ライカ、今完全におっさんだったよ。","ENG":"Ugh, that's so gross. You sound like some sleazy old guy.","TWN":"哎呀，真是太糟糕了。萊卡完全像個大叔。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 고백 같은 건 신중히 생각해. 괜히 잘못 박으면 오히려 어색한 사이 된다고?","JPN":"それに告白とかは慎重に考えな。下手したらかえって気まずくなりかねないから。","ENG":"Well, just think carefully before you confess to someone. One wrong move and it gets super awkward.","TWN":"還有，告白這種事情要慎重考慮。萬一搞錯了，反而會變得尷尬喔？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쟤들처럼 말이야.","JPN":"あいつらみたいに。","ENG":"Just like those two.","TWN":"就像他們一樣。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"흠흠! 이거 다시 봤다고, 얼빵이.","JPN":"おっほん！　見直したよ、間抜け。","ENG":"Ahem! I saw a different side of you, goon.","TWN":"哼哼！？對你有改觀了，小呆瓜。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"마냥 얼빵하기만 한 줄 알았는데, 의외로 대범한 구석이 있잖아?","JPN":"ただ間抜けなだけかと思ったら、意外と大胆なところもあるんだな？","ENG":"Thought you were all clueless, but turns out you've got guts after all.","TWN":"原以為只是個傻乎乎的傢伙，沒想到還有大膽的一面呢？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래, 괜찮아. 이 언니는 네 취향을 존중한단다.","JPN":"いいっていいって。好みって人それぞれだし。","ENG":"It's fine. I support your taste.","TWN":"好吧，沒關係。姊姊尊重你的喜好。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};